export default function Homepage() {
    return (
      <div style={{ padding: "2rem", textAlign: "center" }}>
        <h1>Velkommen til Supportportalen</h1>
        <p style={{ fontSize: "1.2rem", maxWidth: "600px", margin: "1rem auto" }}>
          Her kan du sende inn henvendelser, følge opp saker og få teknisk hjelp – raskt og enkelt.
          Vi er her for å støtte deg med det du trenger.
        </p>
      </div>
    );
  }
